// ─── PDF Parse ───────────────────────────────────────────────────────────────

/**
 * @summary Parse a PDF policy document and extract text
 */
export const parsePolicyPdf = async (
  file: File,
  options?: RequestInit,
): Promise<ParsedPdfResult> => {
  const formData = new FormData();
  formData.append("file", file);
  return customFetch<ParsedPdfResult>(`/api/simulations/parse-pdf`, {
    ...options,
    method: "POST",
    body: formData,
  });
};

export function useParsePolicyPdf<
  TError = ErrorType<unknown>,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof parsePolicyPdf>>,
    TError,
    { file: File },
    unknown
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof parsePolicyPdf>>,
  TError,
  { file: File },
  unknown
> {
  const { mutation: mutationOptions } = options ?? {};

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof parsePolicyPdf>>,
    { file: File }
  > = ({ file }) => parsePolicyPdf(file);

  return useMutation({ mutationFn, ...mutationOptions });
}

// ─── Vote on Message ─────────────────────────────────────────────────────────

export const voteOnMessageUrl = (id: number) => `/api/messages/${id}/vote`;

/**
 * @summary Vote on a message (upvote +1, downvote -1, remove 0)
 */
export const voteOnMessage = async (
  id: number,
  voteBody: VoteBody,
  options?: RequestInit,
): Promise<VoteResult> => {
  return customFetch<VoteResult>(voteOnMessageUrl(id), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...(options?.headers ?? {}) },
    body: JSON.stringify(voteBody),
  });
};

export function useVoteOnMessage<
  TError = ErrorType<unknown>,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof voteOnMessage>>,
    TError,
    { id: number; data: VoteBody },
    unknown
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof voteOnMessage>>,
  TError,
  { id: number; data: VoteBody },
  unknown
> {
  const { mutation: mutationOptions } = options ?? {};

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof voteOnMessage>>,
    { id: number; data: VoteBody }
  > = ({ id, data }) => voteOnMessage(id, data);

  return useMutation({ mutationFn, ...mutationOptions });
}

